// prisma/schema.prisma
generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql" // or sqlite for local dev
  url      = env("DATABASE_URL")
}

model User {
  id        String   @id @default(cuid())
  email     String   @unique
  name      String?
  posts     Post[]
  createdAt DateTime @default(now())
}

model Post {
  id        String   @id @default(cuid())
  title     String
  content   String
  published Boolean  @default(false)
  author    User     @relation(fields: [authorId], references: [id])
  authorId  String
  createdAt DateTime @default(now())
}

import { PrismaClient } from '@prisma/client';
const prisma = new PrismaClient();

// Create a user with a post -- fully typed
const user = await prisma.user.create({
  data: {
    email: 'dev@example.com',
    name: 'Speed Demon',
    posts: {
      create: { title: 'Shipped in 5 min', content: 'Prisma is magic' },
    },
  },
  include: { posts: true }, // Autocomplete knows 'posts' exists
});

// Find users with their posts -- zero SQL
const users = await prisma.user.findMany({
  where: { posts: { some: { published: true } } },
  include: { posts: true },
  orderBy: { createdAt: 'desc' },
});

import Stripe from 'stripe';
import { NextResponse } from 'next/server';

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);

export async function POST(req: Request) {
  const { priceId } = await req.json();

  const session = await stripe.checkout.sessions.create({
    mode: 'payment',
    payment_method_types: ['card'],
    line_items: [{ price: priceId, quantity: 1 }],
    success_url: `${process.env.NEXT_PUBLIC_URL}/success`,
    cancel_url: `${process.env.NEXT_PUBLIC_URL}/cancel`,
  });

  return NextResponse.json({ url: session.url });
}

